{
  "repository": "github.com/sg-evals/cockroach--v24.3.0",
  "base_path": "pkg/kv/kvserver",
  "description": "Raft consensus integration and range lease management in CockroachDB v24.3",

  "raft_integration": {
    "overview": "Raft consensus is driven by a per-replica handleRaftReady pipeline. The Store scheduler dispatches work to processReady, which calls Replica.handleRaftReady. That function acquires raftMu and delegates to handleRaftReadyRaftMuLocked, which calls raft.Ready(), persists log entries via LogStore, applies committed entries through the replicaStateMachine (apply.StateMachine), and sends outbound messages via RaftTransport.",

    "key_files": [
      {
        "path": "pkg/kv/kvserver/replica_raft.go",
        "package": "kvserver",
        "role": "Core Raft processing loop for a single Replica",
        "key_symbols": [
          {
            "name": "handleRaftReady",
            "kind": "method",
            "receiver": "*Replica",
            "line": 832,
            "signature": "func (r *Replica) handleRaftReady(ctx context.Context, inSnap IncomingSnapshot) (handleRaftReadyStats, error)",
            "description": "Public entry point. Acquires raftMu then delegates to handleRaftReadyRaftMuLocked. Processes a raft.Ready batch: stable storage writes, snapshot application, committed-entry application, and message dispatch."
          },
          {
            "name": "handleRaftReadyRaftMuLocked",
            "kind": "method",
            "receiver": "*Replica",
            "line": 867,
            "signature": "func (r *Replica) handleRaftReadyRaftMuLocked(ctx context.Context, inSnap IncomingSnapshot) (stats handleRaftReadyStats, _ error)",
            "description": "Requires raftMu held. Calls raft.RawNode.Ready(), writes log entries to LogStore, applies snapshots, applies committed entries via replicaStateMachine, advances the raft state machine, and sends outbound messages. Also manages RACv2 flow-control level transitions."
          },
          {
            "name": "handleRaftReadyStats",
            "kind": "struct",
            "line": null,
            "description": "Timing and counters returned from handleRaftReady: tBegin, tEnd, snap.offered, etc."
          }
        ],
        "imports_notable": [
          "pkg/kv/kvserver/apply",
          "pkg/kv/kvserver/logstore",
          "pkg/kv/kvserver/raftlog",
          "pkg/kv/kvserver/stateloader",
          "pkg/raft",
          "pkg/raft/raftpb",
          "pkg/kv/kvserver/kvflowcontrol/replica_rac2"
        ]
      },
      {
        "path": "pkg/kv/kvserver/store_raft.go",
        "package": "kvserver",
        "role": "Store-level Raft dispatch: scheduler callbacks, inbound message queuing, snapshot handling",
        "key_symbols": [
          {
            "name": "processReady",
            "kind": "method",
            "receiver": "*Store",
            "line": 671,
            "signature": "func (s *Store) processReady(rangeID roachpb.RangeID)",
            "description": "Called by the raftScheduler when a replica has a pending raft.Ready. Looks up the Replica by rangeID, calls r.handleRaftReady(ctx, noSnap), records RaftWorkingDurationNanos and RaftHandleReadyLatency metrics, and warns if processing exceeded defaultReplicaRaftMuWarnThreshold."
          },
          {
            "name": "processRaftRequestWithReplica",
            "kind": "method",
            "receiver": "*Store",
            "line": 368,
            "signature": "func (s *Store) processRaftRequestWithReplica(...)",
            "description": "Delivers an inbound RaftMessageRequest to a specific Replica, stepping it into the raft state machine."
          },
          {
            "name": "processRaftSnapshotRequest",
            "kind": "method",
            "receiver": "*Store",
