  "range_lease_management": {
    "overview": "Range leases grant a single replica the right to serve reads and propose writes for a key range. CockroachDB v24.3 supports three lease types: expiration-based (LeaseExpiration), epoch-based (LeaseEpoch), and leader-based (LeaseLeader, new). The desired type is chosen per-replica by desiredLeaseTypeRLocked. Lease acquisition is initiated by requestLeaseLocked → pendingLeaseRequest.InitOrJoinRequest, which proposes a RequestLease Raft command. Cooperative transfers use AdminTransferLease → TransferLease command.",

    "lease_types": {
      "LeaseExpiration": {
        "roachpb_constant": "roachpb.LeaseExpiration",
        "description": "Valid while wall_time < lease.Expiration - max_clock_offset. No external dependency. Required for ranges covering the node liveness keyspace (to avoid circular dependencies). Also used when kv.expiration_leases_only.enabled is true.",
        "validity_check": "status.Expiration() compared to now; stasis period = expiration - max_clock_offset"
      },
      "LeaseEpoch": {
        "roachpb_constant": "roachpb.LeaseEpoch",
        "description": "Does not expire by wall clock. Valid as long as the leaseholder's node liveness record epoch matches lease.Epoch. The leaseholder must heartbeat the liveness range periodically. If the node dies, another node increments the epoch (IncrementEpoch), invalidating the old lease.",
        "validity_check": "nl.GetLiveness(nodeID).Epoch == lease.Epoch; expiration derived from liveness record expiration"
      },
      "LeaseLeader": {
        "roachpb_constant": "roachpb.LeaseLeader",
        "description": "New in v24.3. Tied to Raft leader fortification (store liveness). Valid while the Raft leader has support (LeadSupportUntil) from a quorum of stores. Enabled when kv.raft.leader_fortification.fraction_enabled > 0 AND kv.rangefeed.leader_leases.enabled is true. Eliminates dependency on node liveness for non-system ranges.",
        "validity_check": "For local holder: RaftStatus.Term == lease.Term && RaftStatus.LeadSupportUntil > now. For remote: MinExpiration or known successor term."
      }
    },

    "lease_selection_logic": {
      "file": "pkg/kv/kvserver/replica_range_lease.go",
      "function": "desiredLeaseTypeRLocked",
      "line": 810,
      "logic": [
        "1. If requiresExpirationLeaseRLocked() (range covers liveness keyspace) → LeaseExpiration",
        "2. Else if ExpirationLeasesOnly cluster setting enabled (and replica count within limit) → LeaseExpiration",
        "3. Else if replicaRLockedStoreLiveness.SupportFromEnabled() AND LeaderLeasesEnabled setting → LeaseLeader",
        "4. Otherwise → LeaseEpoch"
      ],
      "related_settings": [
        "ExpirationLeasesOnly (kv.expiration_leases_only.enabled)",
        "ExpirationLeasesMaxReplicasPerNode (kv.expiration_leases.max_replicas_per_node)",
        "LeaderLeasesEnabled (kv.rangefeed.leader_leases.enabled)",
        "RaftLeaderFortificationFractionEnabled (kv.raft.leader_fortification.fraction_enabled)"
      ]
    },

