      "        → raft.RawNode.Ready() → raft.Ready{Entries, CommittedEntries, Messages, Snapshot}",
      "        → LogStore.StoreEntries(entries)  [persist to Pebble]",
      "        → replicaStateMachine.ApplyToStateMachine(committedEntries)",
      "          → replicaDecoder.DecodeEntries()",
      "          → replicaAppBatch.Stage(cmd) for each entry",
      "          → replicaAppBatch.ApplyToStateMachine() [atomic Pebble write]",
      "          → handleLeaseResult() [if lease command applied]",
      "        → raft.RawNode.Advance()",
      "        → RaftTransport.SendAsync(outboundMessages)"
    ],
    "lease_acquisition": [
      "Replica.redirectOnOrAcquireLease(ctx)",
      "  → Replica.leaseStatusForRequestRLocked() → leases.Status()",
      "  → [if EXPIRED/UNUSABLE] Replica.requestLeaseLocked(ctx, status, limiter)",
      "    → pendingLeaseRequest.InitOrJoinRequest(ctx, repDesc, status, startKey, ...)",
      "      → [async goroutine] Replica.propose(RequestLeaseRequest)",
      "        → proposalBuf.Insert(proposal)",
      "        → [on commit] batcheval.RequestLease() evaluates command",
      "        → [on apply] handleLeaseResult() updates in-memory lease"
    ],
    "lease_transfer": [
      "Replica.AdminTransferLease(ctx, targetStoreID, bypassSafetyChecks)",
      "  → [wait for in-progress extension]",
      "  → pendingLeaseRequest.InitOrJoinRequest(..., transfer=true)",
      "    → [async goroutine] Replica.propose(TransferLeaseRequest)",
      "      → proposalBuf.Insert(proposal)",
      "      → [on commit] batcheval.TransferLease() evaluates command",
      "        → EvalCtx.RevokeLease() [PROSCRIBED on outgoing leaseholder]",
      "        → writes new lease to RangeLeaseKey",
      "      → [on apply] handleLeaseResult() updates in-memory lease"
    ],
    "epoch_lease_expiry": [
      "Node N dies → stops heartbeating liveness range",
      "After TimeUntilNodeDead: other nodes see liveness record expired",
      "Replica.leaseStatusAtRLocked() → leases.Status() → LeaseState_EXPIRED",
      "  (because liveness.Epoch != lease.Epoch after IncrementEpoch, or expiration passed)",
      "New leaseholder candidate: Replica.requestLeaseLocked()",
      "  → may call NodeLiveness.IncrementEpoch(deadNode) first",
      "  → then proposes RequestLease with new epoch"
    ]
  },

